colors.code_snippet:
:root {
  /* Backgrounds */
  --bg-primary: #21211e;
  --bg-secondary: #2a2a27;
  --bg-code: #1c1c1a;

  /* Text */
  --text-primary: #e6e2d8;
  --text-secondary: #b5b0a4;
  --text-heading: #f0ece2;

  /* Accent — Navy (brand) */
  --accent: #3B6DA5;

  /* Accent-2 — Terracotta */
  --accent-2: #D4785A;

  /* Semantic */
  --green: #7b9e6d;
  --orange: #c98d4e;
  --red: #c06a5a;

  /* Borders */
  --border: #3a3832;
  --border-light: #2e2d28;
}

typography.code_snippet:
/* Display · 标题 */
--font-display: "Noto Serif SC",
  "Source Han Serif SC", "Songti SC", serif;

/* Body · 正文 & UI */
--font-body: "Inter", "Noto Sans SC",
  "PingFang SC", sans-serif;

/* Mono · 代码 & 数据 */
--font-mono: "IBM Plex Mono",
  "SFMono-Regular", monospace;
